// journal-04 loop guard + audio detect + request builder.
// The webhook fires memos.memo.created AND memos.memo.comment.created; creating a
// COMMENT (our reflection) re-fires memo.created carrying the *comment* memo. We
// must analyze ONLY genuine #journal entries and never our own output.
const evt = ($input.first().json && $input.first().json.body) || {};
const activity = evt.activityType || '';
const memo = evt.memo || {};
const content = (memo.content || '').toString();
const tags = Array.isArray(memo.tags) ? memo.tags : [];
const name = memo.name || '';
const SENTINEL = '\u{1F9ED} **Reflection**'; // header our reflection comment starts with

// journal-04: detect an audio attachment. The memo.created webhook carries
// memo.attachments[] inline: {name:"attachments/..", filename, type:"audio/..",
// size, memo}. Pick the FIRST audio attachment as the voice note - no memo
// re-fetch, so the text-only path pays nothing.
const atts = Array.isArray(memo.attachments) ? memo.attachments : [];
const audio = atts.find(a => a && typeof a.type === 'string' && a.type.toLowerCase().startsWith('audio/')) || null;
const hasAudio = !!(audio && audio.name && audio.filename);

// 1) only entry-created events (drops memos.memo.comment.created outright)
if (activity !== 'memos.memo.created') return [];
// 2) must be a journal entry. #gamelog templates also carry #journal; our
//    reflection comment has no #journal, so this tag gate is itself a loop guard.
if (!tags.includes('journal')) return [];
// 3) never re-analyze our own reflection or an already-analyzed marker
if (content.includes(SENTINEL) || content.toLowerCase().includes('#analyzed')) return [];
// 4) need a target, and something to analyze: text OR a voice note (a voice-only
//    entry may carry only the #journal tag as text - allow it through when audio exists)
if (!name) return [];
if (!content.trim() && !hasAudio) return [];

const SYS = "You are a quiet, warm journaling companion. You receive ONE journal entry. Respond ONLY with valid JSON in exactly this schema:\n{\n  \"sentiment\": \"<very negative|negative|neutral|positive|very positive>\",\n  \"mood_score\": <integer 1-10>,\n  \"emotions\": [\"<up to 4>\"],\n  \"themes\": [\"<up to 4>\"],\n  \"summary\": \"<one-sentence reflection of what this entry is about>\",\n  \"coaching\": \"<1-2 sentences, gentle and low-pressure. Reflect back one specific thing. At MOST one soft, open-ended question - and only if it genuinely helps. No advice, no cliches, no cheerleading. It is fine to simply witness.>\"\n}\nBe honest and specific, never saccharine. Stay light - you are a nudge, not a coach. If the entry suggests crisis or self-harm risk, set coaching to gently, briefly encourage reaching out to a trusted person or professional. Never give medical advice.";

// Default (text-only) messages - UNCHANGED behavior when no audio is present. The
// audio branch rebuilds messages after merging the transcript; both reuse SYS.
return [{ json: {
  memoName: name,
  content: content,
  hasAudio: hasAudio,
  audioName: hasAudio ? audio.name : '',
  audioFilename: hasAudio ? audio.filename : '',
  sys: SYS,
  messages: [
    { role: 'system', content: SYS },
    { role: 'user', content: content }
  ]
} }];

// journal-04: merge the whisper transcript into the entry, then rebuild the LLM
// messages so the transcript is analyzed. Fail-safe: if transcription produced
// nothing (whisper down/evicted, or a mis-route), fall back to the text-only
// messages the Guard already built - the primary text path never regresses.
const guard = $('Guard: loop-safe filter').first().json;
let transcript = '';
try {
  const j = $input.first().json;
  if (j && typeof j.text === 'string') transcript = j.text.trim();
} catch (e) { transcript = ''; }

if (!transcript) {
  return [{ json: { memoName: guard.memoName, content: guard.content, messages: guard.messages } }];
}

const base = (guard.content || '').trim();
const merged = base ? (base + '\n\n[Voice note transcript]\n' + transcript)
                    : ('[Voice note transcript]\n' + transcript);
return [{ json: {
  memoName: guard.memoName,
  content: merged,
  messages: [
    { role: 'system', content: guard.sys },
    { role: 'user', content: merged }
  ]
} }];

// Tolerant parse of the (possibly chatty/fenced) LLM reply, then format the
// Markdown reflection. If the model was evicted/OOM'd (VRAM contention on the rig)
// the HTTP node continues on error with no choices -> we post NOTHING (best-effort;
// the journal entry itself is already saved). A chatty reply never breaks the loop.
const guard = $('Guard: loop-safe filter').first().json;
const memoName = guard.memoName;

let text = null;
try {
  const j = $input.first().json;
  if (j && j.choices && j.choices[0] && j.choices[0].message) {
    text = j.choices[0].message.content;
  }
} catch (e) { text = null; }

if (!text || !text.toString().trim()) return []; // LLM unavailable -> no comment

function extractJSON(raw) {
  const t = raw.toString().trim();
  // 1) as-is
  try { return JSON.parse(t); } catch (e) {}
  // 2) inside a ```json ... ``` fence
  const fence = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) { try { return JSON.parse(fence[1].trim()); } catch (e) {} }
  // 3) first '{' .. last '}' (chatty prose around a complete object)
  const a = t.indexOf('{'), b = t.lastIndexOf('}');
  if (a !== -1 && b > a) { try { return JSON.parse(t.slice(a, b + 1)); } catch (e) {} }
  // 4) truncation repair: a small model can drop the closing brace / cut a string
  //    mid-value. Balance an odd trailing quote, then the braces, and retry.
  if (a !== -1) {
    let s = t.slice(a).replace(/[\s,]+$/, '');
    const quotes = (s.match(/(?<!\\)"/g) || []).length;
    if (quotes % 2 === 1) s += '"';
    const open = (s.match(/{/g) || []).length, close = (s.match(/}/g) || []).length;
    if (open > close) s += '}'.repeat(open - close);
    try { return JSON.parse(s); } catch (e) {}
  }
  return null;
}

const obj = extractJSON(text);
if (!obj || typeof obj !== 'object') return []; // unparseable -> best-effort skip

const clampMood = (v) => { const n = parseInt(v, 10); return isNaN(n) ? null : Math.max(1, Math.min(10, n)); };
const sentiment = (obj.sentiment || 'neutral').toString().trim();
const mood = clampMood(obj.mood_score);
const emotions = Array.isArray(obj.emotions) ? obj.emotions.slice(0, 4).map(x => x.toString().trim()).filter(Boolean) : [];
const themes = Array.isArray(obj.themes) ? obj.themes.slice(0, 4).map(x => x.toString().trim()).filter(Boolean) : [];
const coaching = (obj.coaching || '').toString().trim();
if (!coaching) return []; // nothing to say -> stay quiet

const moodStr = mood ? (mood + '/10') : '—';
const parts = [];
if (emotions.length) parts.push('_Emotions:_ ' + emotions.join(', '));
if (themes.length) parts.push('_Themes:_ ' + themes.join(', '));

let md = '\u{1F9ED} **Reflection** · mood ' + moodStr + ' · ' + sentiment;
if (parts.length) md += '\n' + parts.join('  ·  ');
md += '\n\n' + coaching;

return [{ json: { memoName: memoName, comment: md } }];

// journal-07 (Phase 2, OPTIONAL) - IGDB game-metadata enrichment for #gamelog.
// FULLY ISOLATED branch: it taps the same webhook as the core loop but shares NO
// node with it. If disabled or creds are missing this returns [] and the branch
// stops here, so the core reflection loop is entirely unaffected (graceful degrade).
const evt = ($input.first().json && $input.first().json.body) || {};
const activity = evt.activityType || '';
const memo = evt.memo || {};
const content = (memo.content || '').toString();
const tags = Array.isArray(memo.tags) ? memo.tags : [];
const name = memo.name || '';

// Master toggle (env). Absent/empty => enabled (this branch only exists post opt-in);
// set IGDB_ENABLED=false to disable Phase 2 WITHOUT touching the core loop.
const flag = ($env.IGDB_ENABLED || 'true').toString().trim().toLowerCase();
if (['0', 'false', 'off', 'no', 'disabled'].includes(flag)) return [];

// Graceful degradation: no creds => skip silently (the core analysis still runs).
const clientId = ($env.IGDB_CLIENT_ID || '').toString().trim();
const clientSecret = ($env.IGDB_CLIENT_SECRET || '').toString().trim();
if (!clientId || !clientSecret) return [];

// Loop-safe: only genuine new #gamelog entries. Our own metadata/reflection comments
// fire memos.memo.comment.created and never carry #gamelog, so they are dropped twice
// over (activity gate + tag gate); the sentinel is a third belt-and-suspenders guard.
const SENTINEL = '\u{1F3AE} **'; // the header our metadata comment starts with
if (activity !== 'memos.memo.created') return [];
if (!tags.includes('gamelog')) return [];
if (!name) return [];
if (content.includes(SENTINEL)) return [];

// Parse the game title. The #gamelog template puts it on a "**Game:** <title>" line;
// fall back to the first meaningful (non-tag / non-scaffold) line for free-form entries.
function parseTitle(body) {
  const lines = body.split(/\r?\n/);
  for (const raw of lines) {
    const m = raw.match(/\*\*\s*Game\s*:?\s*\*\*\s*:?\s*(.+)$/i) || raw.match(/^\s*Game\s*:\s*(.+)$/i);
    if (m && m[1]) {
      const t = m[1].replace(/#[\w-]+/g, '').replace(/[*_`>#]/g, '').trim();
      if (t) return t;
    }
  }
  for (const raw of lines) {
    let t = raw.replace(/#[\w-]+/g, '').trim();           // strip hashtags anywhere
    if (!t) continue;
    if (/^\*\*[^*]+:\*\*\s*$/.test(t)) continue;           // empty "**Field:**" scaffold
    if (/^#{1,6}\s/.test(t)) continue;                     // "## What I did"
    if (/^[-*]\s*$/.test(t)) continue;                     // empty bullet
    if (/^_+\/?\d*_*$/.test(t)) continue;                  // "_/10_"
    t = t.replace(/[*_`>]/g, '').trim();
    if (t) return t;
  }
  return '';
}
const gameTitle = parseTitle(content);
if (!gameTitle) return [];

return [{ json: { memoName: name, gameTitle, clientId, clientSecret } }];

// journal-07: pick the best IGDB match and render a tidy, loop-safe metadata COMMENT
// (cover thumbnail + canonical facts). No match / OAuth or IGDB unreachable => return
// [] so nothing is posted and the core reflection (a separate branch) is untouched.
const guard = $('IGDB Guard: gamelog filter').first().json;
const memoName = guard.memoName;
const title = (guard.gameTitle || '').toString();

// Collect result games whether or not the HTTP node split the JSON array into items.
let games = [];
const all = $input.all().map(i => i.json);
if (all.length === 1 && Array.isArray(all[0])) games = all[0];
else games = all;
games = (games || []).filter(g => g && typeof g === 'object' && g.name);
if (!games.length) return []; // no match / OAuth or search failed -> stay silent

const norm = s => (s || '').toString().toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
const nt = norm(title);
const hasDev = g => Array.isArray(g.involved_companies) && g.involved_companies.some(c => c && c.developer);
// category is often omitted for main games (default 0) and is being phased out by IGDB;
// treat missing as "main", never as a reason to exclude.
const isMain = g => { const t = g.category; return t === undefined || t === null || t === 0; };

const exact = games.filter(g => norm(g.name) === nt);
let pool = exact.length ? exact : games;
const mains = pool.filter(isMain);
if (mains.length) pool = mains;
pool.sort((a, b) => {
  const da = hasDev(a) ? 0 : 1, db = hasDev(b) ? 0 : 1;
  if (da !== db) return da - db;                    // prefer an entry with a known developer
  const ra = a.first_release_date || Infinity, rb = b.first_release_date || Infinity;
  return ra - rb;                                   // then the earliest (original) release
});
const g = pool[0];

const canonical = (g.name || title).toString().trim();
let releaseStr = '';
if (g.first_release_date) {
  const d = new Date(g.first_release_date * 1000);
  if (!isNaN(d.getTime())) releaseStr = d.toISOString().slice(0, 10);
}
const genres = Array.isArray(g.genres) ? g.genres.map(x => x && x.name).filter(Boolean) : [];
const devs = Array.isArray(g.involved_companies)
  ? g.involved_companies.filter(c => c && c.developer && c.company).map(c => c.company.name).filter(Boolean)
  : [];
const cover = g.cover && g.cover.image_id
  ? ('https://images.igdb.com/igdb/image/upload/t_cover_big/' + g.cover.image_id + '.jpg')
  : '';
const igdbUrl = g.url || '';

let md = '\u{1F3AE} **' + canonical + '**';
if (releaseStr) md += ' · ' + releaseStr.slice(0, 4);
md += '\n';
const facts = [];
if (releaseStr) facts.push('_Released:_ ' + releaseStr);
if (genres.length) facts.push('_Genres:_ ' + genres.join(', '));
if (devs.length) facts.push('_Developer:_ ' + devs.join(', '));
if (facts.length) md += facts.join('  ·  ') + '\n';
if (cover) md += '\n![cover](' + cover + ')\n';
if (igdbUrl) md += '\n[View on IGDB](' + igdbUrl + ')';
md += '\n\n_via IGDB — auto-matched from your #gamelog title._';

return [{ json: { memoName, comment: md } }];
